dslRuleAfterChange:
/*!id: string.replaceall.remove-pattern-quote*/
/*!description: Replaces String.replaceAll(Pattern.quote(s), Matcher.quoteReplacement(r)) with String.replace(s, r) to avoid unnecessary regex overhead.*/
/*!severity: info*/
java.lang.String.$str.replaceAll(java.util.regex.Pattern.quote($pattern), java.util.regex.Matcher.quoteReplacement($replacement))
=> $str.replace($pattern, $replacement)
;;

/*!id: string.replaceall.single-char-to-char-literal*/
/*!description: Replaces String.replaceAll(singleCharLiteral, singleCharLiteral) with String.replace(charLiteral, charLiteral) for performance and conciseness.*/
/*!severity: info*/
$str.replaceAll($pattern, $replacement) :: isStringLiteral($pattern) && isSingleCharacter($pattern) && isStringLiteral($replacement) && isSingleCharacter($replacement)
=> $str.replace($pattern.charAt(0), $replacement.charAt(0))
;;

commitMessage:
Bug 572048 - Exit loop early results in wrong logic

Given:
for (byte element : alphaData) {
	int alpha = element & 0xFF;
	if (!(alpha == 0 || alpha == 255)) {
		/* Full alpha channel transparency */
		return imageData;
	}
	if (!transparency && alpha == 0) {
		transparency = true;
	}
}

When:
Applying "Break loop" cleanup

Expected:
(same)

Actual:
for (byte element : alphaData) {
	int alpha = element & 0xFF;
	if (!(alpha == 0 || alpha == 255)) {
		/* Full alpha channel transparency */
		return imageData;
	}
	if (!transparency && alpha == 0) {
		transparency = true;
		break;
	}
}

